const assertDamagesCoveredByPolicy = (
  insuredItems: Item[],
  damages: Damage[],
): void => {
  const insuredCounts = countByType(insuredItems);
  const damageCounts: Record<string, number> = {};
  for (const damage of damages) {
    damageCounts[damage.itemType] = (damageCounts[damage.itemType] ?? 0) + 1;
    if (damageCounts[damage.itemType] > (insuredCounts[damage.itemType] ?? 0)) {
      throw new Error(`Item type not in policy: ${damage.itemType}`);
    }
  }
};
